#include <bits/stdc++.h>
using namespace std;

int main() {
    int N;
    cin >> N;

    int total = 0;
    int cntC = 0, cntR = 0, cntF = 0;

    for (int i = 0; i < N; ++i) {
        int num;
        char type;
        cin >> num >> type;
        total += num;
        if (type == 'C') cntC += num;
        else if (type == 'R') cntR += num;
        else if (type == 'F') cntF += num;
    }

    cout << "Total: " << total << " weapons\n";
    cout << "Total swords: " << cntC << "\n";
    cout << "Total blades: " << cntR << "\n";
    cout << "Total spears: " << cntF << "\n";

    cout << fixed << setprecision(2);
    cout << "Percentage of swords: " << (cntC * 100.0 / total) << " %\n";
    cout << "Percentage of blades: " << (cntR * 100.0 / total) << " %\n";
    cout << "Percentage of spears: " << (cntF * 100.0 / total) << " %\n";

    return 0;
}
